module.exports = async function(data) {
	// Do something...
     const com_rules = data.item_read_nm6c3.com_issue.Com_Issues_c
     const selected_rule = com_rules[0];
    if(com_rules.length>1) {
   const frequency_count = data.get_req_frequency[0].count;
        if(frequency_count>1) {
   selected_rule = com_rules.find(rule => {
        return (
            frequency_count >= (rule.frequrency_from || 0) &&
            frequency_count <= (rule.frequrency_to || Infinity)
        );
    });
        }

    }


let amount = 0;

switch (selected_rule.compensation_type) {
  case "DELIVERY":
    amount = data.item_read_nm6c3.delivery_fee > 0
      ? data.item_read_nm6c3.delivery_fee
      : selected_rule.fallback_value;
    break;

  case "ORDER":
    amount = selected_rule.max_amount
      ? Math.min(data.item_read_nm6c3.order_value, selected_rule.max_amount)
      : data.$trigger.order_value;
    break;

  case "FIXED":
    amount = selected_rule.fixed_amount;
    break;

  case "PERCENT":
       if(data.item_read_nm6c3.order_value ==null || data.item_read_nm6c3.order_value <=0) {
           if(data.item_read_nm6c3.user_complaint_amount !=null && data.item_read_nm6c3.user_complaint_amount >0){
            amount = (data.item_read_nm6c3.user_complaint_amount * selected_rule.percentage) / 100; }
       }
        else 
        { amount = (data.item_read_nm6c3.order_value * selected_rule.percentage) / 100;
        }
    if (selected_rule.max_amount) amount = Math.min(amount, selected_rule.max_amount);
    break;

  case "ITEMS":
    amount = data.item_read_nm6c3.items_with_issue.reduce(
      (sum, item) => sum + item.price, 0
    );
    break;

  case "COMPOSITE":
    amount = selected_rule.components.reduce((sum, c) => {
      if (c.type === "ORDER") {
        return sum + Math.min(data.$trigger.order_value, c.max_amount);
      }
      if (c.type === "PERCENT") {
        return sum + Math.min(
          (data.item_read_nm6c3.order_value * c.percentage) / 100,
          c.max_amount
        );
      }
      return sum;
    }, 0);
    break;
}

return {
  suggested_compensation: {
     user_complaint_amount: data.$trigger.user_complaint_amount,
    type: selected_rule.compensation_type,
    amount:Math.round(amount)
  }
};

}
